package devportal

import (
	"context"

	"google.golang.org/grpc"
	"google.golang.org/protobuf/types/known/durationpb"
	"google.golang.org/protobuf/types/known/emptypb"

	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/generated/protos/types/devvit/devportal"
	"github.snooguts.net/reddit/reddit-devplatform-monorepo/go-common/grpc/proxyutil"
)

type EventsProxy struct {
	devportal.UnimplementedEventsServer
	client devportal.EventsClient
}

func init() {
	proxyutil.Register(&devportal.Events_ServiceDesc, NewEventsProxy)
}
func NewEventsProxy(cc grpc.ClientConnInterface) devportal.EventsServer {
	return &EventsProxy{client: devportal.NewEventsClient(cc)}
}
func (p *EventsProxy) SendEvent(ctx context.Context, in *durationpb.Value) (*emptypb.Empty, error) {
	return proxyutil.ProxyMethod[durationpb.Value, emptypb.Empty](p.client.SendEvent)(ctx, in)
}
